import { create, StateCreator } from 'zustand';

type Ticker = { id: string; price: number; prices: number[]; ts: number };
type Store = {
  tickers: Record<string, Ticker>;
  applyBatch: (updates: Ticker[]) => void;
};

type RecordedAction = { type: string; payload: unknown; ts: number };

const recorder =
  <T>(config: StateCreator<T>): StateCreator<T> =>
  (set, get, api) => {
    const log: RecordedAction[] = [];
    const wrappedSet: typeof set = ((partial, replace) => {
      log.push({ type: 'set', payload: partial, ts: performance.now() });
      if (log.length > 1000) log.shift();
      return set(partial as Parameters<typeof set>[0], replace as false | undefined);
    }) as typeof set;
    (api as unknown as { getLog: () => RecordedAction[] }).getLog = () => log;
    return config(wrappedSet, get, api);
  };

export const useStore = create<Store>()(
  recorder((set) => ({
    tickers: {},
    applyBatch: (updates) =>
      set((s) => {
        const next = { ...s.tickers };
        for (const u of updates) {
          const prev = next[u.id];
          next[u.id] = {
            ...u,
            prices: prev ? [...prev.prices.slice(-29), u.price] : [u.price],
          };
        }
        return { tickers: next };
      }),
  }))
);

const buffer: Ticker[] = [];
let rafHandle: number | null = null;

export function onWsMessage(t: Ticker) {
  buffer.push(t);
  if (rafHandle === null) {
    rafHandle = requestAnimationFrame(() => {
      const batch = buffer.splice(0);
      rafHandle = null;
      if (batch.length > 0) useStore.getState().applyBatch(batch);
    });
  }
}

export function TickerCard({ id }: { id: string }) {
  const ticker = useStore((s) => s.tickers[id]);
  if (!ticker) return null;
  return <div>{ticker.price.toFixed(2)}</div>;
}

import { createSlice, createEntityAdapter, configureStore } from '@reduxjs/toolkit';

type Ticker = { id: string; price: number; prices: number[]; ts: number };

const tickersAdapter = createEntityAdapter<Ticker>();

const tickersSlice = createSlice({
  name: 'tickers',
  initialState: tickersAdapter.getInitialState(),
  reducers: {
    applyBatch: (state, action: { payload: Ticker[] }) => {
      for (const u of action.payload) {
        const prev = state.entities[u.id];
        const next: Ticker = {
          ...u,
          prices: prev ? [...prev.prices.slice(-29), u.price] : [u.price],
        };
        tickersAdapter.upsertOne(state, next);
      }
    },
  },
});

export const store = configureStore({
  reducer: { tickers: tickersSlice.reducer },
});

export const { selectById: selectTicker } = tickersAdapter.getSelectors(
  (s: ReturnType<typeof store.getState>) => s.tickers
);

export function TickerCard({ id }: { id: string }) {
  const ticker = useAppSelector((s) => selectTicker(s, id));
  if (!ticker) return null;
  return <div>{ticker.price.toFixed(2)}</div>;
}

declare function useAppSelector<T>(fn: (s: ReturnType<typeof store.getState>) => T): T;

type ToolDef = {
  id: string;
  label: string;
  icon: React.ReactNode;
  shortcut?: string;
  command: (editor: Editor) => void;
  isAvailable?: (editor: Editor) => boolean;
};

declare class Editor {
  state: { selection: unknown; isReadOnly: boolean };
  exec(cmd: string): void;
}

export const toolRegistry = {
  bold: { id: 'bold', label: 'Bold', icon: <BoldIcon />, shortcut: 'Mod+B', command: (e: Editor) => e.exec('bold') },
  italic: { id: 'italic', label: 'Italic', icon: <ItalicIcon />, shortcut: 'Mod+I', command: (e: Editor) => e.exec('italic') },
  mention: { id: 'mention', label: 'Mention', icon: <AtIcon />, command: (e: Editor) => e.exec('mention'), isAvailable: (e: Editor) => !e.state.isReadOnly },
} satisfies Record<string, ToolDef>;

const EditorCtx = React.createContext<Editor | null>(null);

export function ToolbarButton({ toolId }: { toolId: keyof typeof toolRegistry }) {
  const editor = React.useContext(EditorCtx);
  const tool = toolRegistry[toolId];
  if (!editor) return null;
  const available = tool.isAvailable?.(editor) ?? true;
  if (!available) return null;
  return (
    <button type="button" aria-label={tool.label} onClick={() => tool.command(editor)}>
      {tool.icon}
    </button>
  );
}

export function CommentToolbar() {
  return (
    <div role="toolbar" aria-label="Comment toolbar">
      <ToolbarButton toolId="bold" />
      <ToolbarButton toolId="italic" />
      <ToolbarButton toolId="mention" />
    </div>
  );
}

