import { useForm } from '@tanstack/react-form';
import { useMachine } from '@xstate/react';
import { createMachine } from 'xstate';
import { z } from 'zod';

const intakeSchema = z.object({
  patientType: z.enum(['inpatient', 'outpatient']),
  age: z.number().min(0).max(120),
  height: z.number().positive(),
  weight: z.number().positive(),
  medications: z.array(z.string()).optional(),
}).refine((d) => !(d.age < 18 && d.patientType === 'outpatient'), {
  message: 'Minors require inpatient flow',
  path: ['patientType'],
});

type Intake = z.infer<typeof intakeSchema>;

const flowMachine = createMachine({
  id: 'intake',
  initial: 'demographics',
  states: {
    demographics: { on: { NEXT: 'vitals' } },
    vitals: { on: { NEXT: 'medications', BACK: 'demographics' } },
    medications: { on: { NEXT: 'review', BACK: 'vitals' } },
    review: { on: { SUBMIT: 'submitted', BACK: 'medications' } },
    submitted: { type: 'final' },
  },
});

type AuditEntry = { field: string; from: unknown; to: unknown; ts: number };
const auditLog: AuditEntry[] = [];

export function IntakeForm() {
  const [state, send] = useMachine(flowMachine);
  const form = useForm<Intake>({
    defaultValues: { patientType: 'outpatient', age: 0, height: 0, weight: 0 },
    validators: { onChange: ({ value }) => intakeSchema.safeParse(value).error?.flatten().fieldErrors },
    onSubmit: async ({ value }) => { await persist(value); send({ type: 'SUBMIT' }); },
  });

  return (
    <form onSubmit={(e) => { e.preventDefault(); form.handleSubmit(); }}>
      {state.matches('demographics') && (
        <form.Field name="age">
          {(field) => (
            <label>Age
              <input
                type="number"
                value={field.state.value}
                onChange={(e) => {
                  const next = Number(e.target.value);
                  auditLog.push({ field: 'age', from: field.state.value, to: next, ts: Date.now() });
                  field.handleChange(next);
                }}
              />
            </label>
          )}
        </form.Field>
      )}
      {state.matches('demographics') && <button type="button" onClick={() => send({ type: 'NEXT' })}>Next</button>}
    </form>
  );
}

declare function persist(v: Intake): Promise<void>;

