import { Suspense } from 'react';
import { unstable_cache } from 'next/cache';

const getProduct = unstable_cache(async (id: string) => {
  const r = await fetch(`https://api.example.com/products/${id}`, { next: { revalidate: 300 } });
  return r.json() as Promise<Product>;
}, ['product'], { revalidate: 300 });

const getInventory = async (id: string) => {
  const r = await fetch(`https://api.example.com/inventory/${id}`, { next: { revalidate: 30 } });
  return r.json() as Promise<Inventory>;
};

export default async function ProductPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const [product, inventory] = await Promise.all([getProduct(id), getInventory(id)]);
  return (
    <main>
      <ProductHero product={product} inventory={inventory} />
      <Suspense fallback={<RecommendationsSkeleton />}>
        <Recommendations productId={id} />
      </Suspense>
      <Suspense fallback={<ReviewsSkeleton />}>
        <ReviewsInitial productId={id} />
      </Suspense>
      <UserPricing productId={id} />
    </main>
  );
}

async function Recommendations({ productId }: { productId: string }) {
  const r = await fetch(`https://api.example.com/recs/${productId}`, { next: { revalidate: 3600 } });
  const recs = (await r.json()) as Product[];
  return <RecommendationsView recs={recs} />;
}

async function ReviewsInitial({ productId }: { productId: string }) {
  const r = await fetch(`https://api.example.com/reviews/${productId}?page=1`);
  const data = (await r.json()) as { reviews: Review[]; total: number };
  return <ReviewsClient initial={data} productId={productId} />;
}

