// types/brand.ts
declare const brand: unique symbol;
type Brand<T, B> = T & { readonly [brand]: B };

export type UserId = Brand<string, 'UserId'>;
export type OrgId = Brand<string, 'OrgId'>;
export type ProductId = Brand<string, 'ProductId'>;
export type Email = Brand<string, 'Email'>;

export function userId(s: string): UserId {
  if (!/^usr_[a-zA-Z0-9]{16}$/.test(s)) throw new Error(`Invalid UserId: ${s}`);
  return s as UserId;
}
export function orgId(s: string): OrgId {
  if (!/^org_[a-zA-Z0-9]{16}$/.test(s)) throw new Error(`Invalid OrgId: ${s}`);
  return s as OrgId;
}
export function email(s: string): Email {
  const trimmed = s.trim().toLowerCase();
  if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(trimmed)) throw new Error(`Invalid email: ${s}`);
  return trimmed as Email;
}

// usage
import { useQuery } from '@tanstack/react-query';

type User = { id: UserId; orgId: OrgId; email: Email; name: string };

async function fetchUser(id: UserId): Promise<User> {
  const r = await fetch(`/api/users/${id}`);
  const data = (await r.json()) as { id: string; orgId: string; email: string; name: string };
  return {
    id: userId(data.id),
    orgId: orgId(data.orgId),
    email: email(data.email),
    name: data.name,
  };
}

export function UserDetail({ id }: { id: UserId }) {
  const { data } = useQuery({ queryKey: ['user', id], queryFn: () => fetchUser(id) });
  return <div>{data?.name}</div>;
}

