import { createContext, useContext, useMemo, useCallback, memo, useState } from 'react';

type Theme = { primary: string; surface: string };
const ThemeCtx = createContext<{ theme: Theme; setPrimary: (p: string) => void } | null>(null);

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setTheme] = useState<Theme>({ primary: '#3b82f6', surface: '#fff' });
  const setPrimary = useCallback((p: string) => setTheme((t) => ({ ...t, primary: p })), []);
  // [memo-cat-1] Context value: stable identity prevents all consumers from re-rendering
  const value = useMemo(() => ({ theme, setPrimary }), [theme, setPrimary]);
  return <ThemeCtx.Provider value={value}>{children}</ThemeCtx.Provider>;
}

export function useTheme() {
  const v = useContext(ThemeCtx);
  if (!v) throw new Error('ThemeProvider missing');
  return v;
}

type RowProps = { id: string; name: string; onSelect: (id: string) => void };
const Row = memo(function Row({ id, name, onSelect }: RowProps) {
  return <li onClick={() => onSelect(id)}>{name}</li>;
});

export function List({ items }: { items: { id: string; name: string }[] }) {
  const [selected, setSelected] = useState<string | null>(null);
  // [memo-cat-2] Callback passed to memo'd child: prevents per-item re-render
  const handleSelect = useCallback((id: string) => setSelected(id), []);
  // [memo-cat-3] Derived value over large data: avoid recomputing on every render
  const sorted = useMemo(() => [...items].sort((a, b) => a.name.localeCompare(b.name)), [items]);
  return (
    <ul>
      {sorted.map((item) => (
        <Row key={item.id} id={item.id} name={item.name} onSelect={handleSelect} />
      ))}
      {selected && <span>Selected: {selected}</span>}
    </ul>
  );
}

// Counter-example: no memoization here, intentionally
export function Counter() {
  const [n, setN] = useState(0);
  // No useCallback - native button doesn't care about reference identity
  return <button onClick={() => setN(n + 1)}>{n}</button>;
}

