import { ErrorBoundary, FallbackProps } from 'react-error-boundary';
import { useState, useCallback } from 'react';

type WidgetMeta = { id: string; domain: string };

function WidgetFallback({ error, resetErrorBoundary, meta }: FallbackProps & { meta: WidgetMeta }) {
  return (
    <div className="rounded-md border border-danger/30 bg-danger/5 p-4 text-sm">
      <div className="font-medium">Widget unavailable</div>
      <div className="text-muted-foreground">{meta.domain} • {error.name}</div>
      <button onClick={resetErrorBoundary} className="mt-2 text-xs underline">Retry</button>
    </div>
  );
}

export function WidgetBoundary({ meta, children }: { meta: WidgetMeta; children: React.ReactNode }) {
  const onError = useCallback((error: Error) => {
    telemetry.error('widget_render_failure', { widgetId: meta.id, domain: meta.domain, error: error.message });
  }, [meta]);
  return (
    <ErrorBoundary fallbackRender={(p) => <WidgetFallback {...p} meta={meta} />} onError={onError} resetKeys={[meta.id]}>
      {children}
    </ErrorBoundary>
  );
}

export function DashboardSection({ id, title, children }: { id: string; title: string; children: React.ReactNode }) {
  const onError = useCallback((error: Error) => {
    telemetry.error('section_render_failure', { sectionId: id, error: error.message });
  }, [id]);
  return (
    <section>
      <h2>{title}</h2>
      <ErrorBoundary
        fallbackRender={({ resetErrorBoundary }) => (
          <div className="rounded-md border border-danger/30 bg-danger/5 p-6">
            <div className="font-medium">{title} unavailable</div>
            <button onClick={resetErrorBoundary}>Retry section</button>
          </div>
        )}
        onError={onError}
      >
        {children}
      </ErrorBoundary>
    </section>
  );
}

