import { Project, SyntaxKind } from 'ts-morph';

const project = new Project({ tsConfigFilePath: 'tsconfig.json' });
project.getSourceFiles().forEach((sf) => {
  sf.forEachDescendant((node) => {
    if (node.getKind() !== SyntaxKind.ElementAccessExpression) return;
    const access = node.asKindOrThrow(SyntaxKind.ElementAccessExpression);
    const type = access.getType();
    if (!type.isUndefined() && !type.isUnion()) return;
    // Check if already null-checked in parent context
    const parent = access.getParent();
    if (parent?.getKind() === SyntaxKind.NonNullExpression) return;
    // Heuristic: if next sibling is '?', leave it
    // Otherwise wrap in safe access
    access.replaceWithText(`${access.getText()} as NonNullable<typeof ${access.getText()}>`);
  });
});
project.saveSync();

