import { signal, computed, effect } from '@preact/signals-react';
import { useSignals } from '@preact/signals-react/runtime';

type Ticker = { symbol: string; price: ReturnType<typeof signal<number>>; volume: ReturnType<typeof signal<number>> };

const tickers = new Map<string, Ticker>();

export function createTicker(symbol: string) {
  const t: Ticker = { symbol, price: signal(0), volume: signal(0) };
  tickers.set(symbol, t);
  return t;
}

// WS feed pushes:
export function applyTick(symbol: string, price: number, volume: number) {
  const t = tickers.get(symbol);
  if (!t) return;
  t.price.value = price;
  t.volume.value = volume;
}

export function TickerRow({ symbol }: { symbol: string }) {
  useSignals();
  const t = tickers.get(symbol)!;
  return (
    <tr>
      <td>{symbol}</td>
      <td>{t.price.value.toFixed(2)}</td>
      <td>{t.volume.value.toLocaleString()}</td>
    </tr>
  );
}

type Listener = () => void;

class TickerStore {
  private state: { price: number; volume: number } = { price: 0, volume: 0 };
  private listeners = new Set<Listener>();

  apply(price: number, volume: number) {
    this.state = { price, volume };
    this.listeners.forEach((l) => l());
  }

  subscribe = (l: Listener) => {
    this.listeners.add(l);
    return () => { this.listeners.delete(l); };
  };

  getSnapshot = () => this.state;
}

const stores = new Map<string, TickerStore>();

export function getStore(symbol: string) {
  let s = stores.get(symbol);
  if (!s) { s = new TickerStore(); stores.set(symbol, s); }
  return s;
}

export function applyTick(symbol: string, price: number, volume: number) {
  getStore(symbol).apply(price, volume);
}

export function TickerRow({ symbol }: { symbol: string }) {
  const store = getStore(symbol);
  const { price, volume } = useSyncExternalStore(store.subscribe, store.getSnapshot);
  return (
    <tr>
      <td>{symbol}</td>
      <td>{price.toFixed(2)}</td>
      <td>{volume.toLocaleString()}</td>
    </tr>
  );
}

