type FieldCtx = { id: string; name: string; error?: string };
const Ctx = createContext<FieldCtx | null>(null);
function useField() { const c = useContext(Ctx); if (!c) throw new Error('use within <Field>'); return c; }

export function Field({ name, error, children }: { name: string; error?: string; children: ReactNode }) {
  const id = useId();
  return <Ctx.Provider value={{ id, name, error }}><div className="space-y-1">{children}</div></Ctx.Provider>;
}

Field.Label = function FieldLabel({ children }: { children: ReactNode }) {
  const { id } = useField();
  return <label htmlFor={id} className="block text-sm font-medium">{children}</label>;
};

Field.Input = function FieldInput(props: React.InputHTMLAttributes<HTMLInputElement>) {
  const { id, error } = useField();
  return <input id={id} aria-invalid={!!error} {...props} className="input" />;
};

Field.Helper = function FieldHelper({ children }: { children: ReactNode }) {
  const { error } = useField();
  if (error) return null;
  return <p className="text-xs text-muted-foreground">{children}</p>;
};

Field.Error = function FieldError() {
  const { error } = useField();
  if (!error) return null;
  return <p className="text-xs text-danger" role="alert">{error}</p>;
};

